const handleReorder = useCallback(async (dragIndex: number, dropIndex: number) => {
  if (dragIndex === dropIndex) return;
  const newTasks = [...tasks];
  const [item] = newTasks.splice(dragIndex, 1);
  newTasks.splice(dropIndex, 0, item);
  setTasks(newTasks);
  await reorderTasks(newTasks.map(t => t.id));
}, [tasks]);
